//! Q6_K mat-vec via bit-plane dilation + LUT — the Q4_K technique at 6-bit.
//!
//! Q6_K weight is affine in its 6-bit quant: `w = (d·sc)·(q − 32)`, one `sc` per
//! 16-element region.  So `Σ w·x = Σ_region A·(Σ q·x − 32·Σ x)` with `A = d·sc`,
//! `B = −32·A`.  The nibble term lifts into 6 bit-planes (q ∈ 0..63), each a
//! subset-sum a LUT replaces.  NOTE: 6 planes × (16/4) groups = 24 lookups vs 16
//! multiplies — a worse op-ratio than Q4_K (4-bit), so the win is expected to be
//! smaller; this module exists to MEASURE that, honestly.

use crate::math::f16_to_f32;

const GROUP: usize = 4;
const REGION: usize = 16; // one Q6_K scale per 16 elements
const GROUPS_PER_REGION: usize = REGION / GROUP; // 4
const PLANES: usize = 6; // 6-bit quant

/// Decode a Q6_K row into (qval[c] ∈ 0..63, A[region]); mirrors `dequantize_q6k_row`.
fn decode_q6k_row(w: &[u8], r: usize, d: usize, qval: &mut [u8], a: &mut [f32]) {
    let bpr = d / 256;
    let row = &w[r * bpr * 210..(r + 1) * bpr * 210];
    for b in 0..bpr {
        let bp = &row[b * 210..(b + 1) * 210];
        let ql = &bp[0..128];
        let qh = &bp[128..192];
        let sc = &bp[192..208]; // i8 scales
        let d_val = f16_to_f32(u16::from_le_bytes([bp[208], bp[209]]));
        for g in 0..2 {
            let qls = &ql[g * 64..g * 64 + 64];
            let qhs = &qh[g * 32..g * 32 + 32];
            for l in 0..32 {
                let is = l / 16;
                let q1 = (qls[l] & 0xf) | ((qhs[l] & 3) << 4);
                let q2 = (qls[l + 32] & 0xf) | (((qhs[l] >> 2) & 3) << 4);
                let q3 = (qls[l] >> 4) | (((qhs[l] >> 4) & 3) << 4);
                let q4 = (qls[l + 32] >> 4) | (((qhs[l] >> 6) & 3) << 4);
                let base = b * 256 + g * 128;
                let s8 = |i: usize| (sc[i] as i8) as f32;
                for (off, q, sci) in [(l, q1, is), (l + 32, q2, is + 2), (l + 64, q3, is + 4), (l + 96, q4, is + 6)] {
                    let c = base + off;
                    qval[c] = q;
                    a[c / REGION] = d_val * s8(g * 8 + sci);
                }
            }
        }
    }
}

pub struct Q6kBitplanes {
    pub n: usize,
    pub d: usize,
    regions: usize, // d / 16
    a: Vec<f32>,    // [n*regions]  A = d*sc
    masks: Vec<u8>, // [n*regions*PLANES*GROUPS_PER_REGION]
}

pub fn q6k_to_bitplanes(w: &[u8], n: usize, d: usize) -> Q6kBitplanes {
    let regions = d / REGION;
    let mut a = vec![0.0f32; n * regions];
    let mut masks = vec![0u8; n * regions * PLANES * GROUPS_PER_REGION];
    let mut qval = vec![0u8; d];
    let mut arow = vec![0.0f32; regions];
    for r in 0..n {
        decode_q6k_row(w, r, d, &mut qval, &mut arow);
        for reg in 0..regions {
            a[r * regions + reg] = arow[reg];
            for g in 0..GROUPS_PER_REGION {
                for plane in 0..PLANES {
                    let mut m = 0u8;
                    for i in 0..GROUP {
                        let q = qval[reg * REGION + g * GROUP + i];
                        m |= ((q >> plane) & 1) << i;
                    }
                    let idx = ((r * regions + reg) * PLANES + plane) * GROUPS_PER_REGION + g;
                    masks[idx] = m;
                }
            }
        }
    }
    Q6kBitplanes { n, d, regions, a, masks }
}

/// Scalar float-LUT reference (exact; validates the format + decomposition).
pub fn mat_vec_q6k_lut_scalar(out: &mut [f32], x: &[f32], bp: &Q6kBitplanes) {
    let regs = bp.regions;
    let mut lut = vec![0.0f32; regs * GROUPS_PER_REGION * 16];
    let mut sx = vec![0.0f32; regs];
    for reg in 0..regs {
        let mut tot = 0.0f32;
        for g in 0..GROUPS_PER_REGION {
            let base = &x[reg * REGION + g * GROUP..reg * REGION + g * GROUP + GROUP];
            let o = &mut lut[(reg * GROUPS_PER_REGION + g) * 16..(reg * GROUPS_PER_REGION + g) * 16 + 16];
            o[0] = 0.0;
            for mm in 1..16usize {
                let low = mm.trailing_zeros() as usize;
                o[mm] = o[mm & (mm - 1)] + base[low];
            }
            tot += base.iter().sum::<f32>();
        }
        sx[reg] = tot;
    }
    for r in 0..bp.n {
        let mut acc = 0.0f32;
        for reg in 0..regs {
            let mut qdot = 0.0f32;
            for plane in 0..PLANES {
                let mut sp = 0.0f32;
                for g in 0..GROUPS_PER_REGION {
                    let idx = ((r * regs + reg) * PLANES + plane) * GROUPS_PER_REGION + g;
                    sp += lut[(reg * GROUPS_PER_REGION + g) * 16 + bp.masks[idx] as usize];
                }
                qdot += ((1u32 << plane) as f32) * sp;
            }
            // w = A(q-32) -> contribution = A*(qdot - 32*Sx)
            acc += bp.a[r * regs + reg] * (qdot - 32.0 * sx[reg]);
        }
        out[r] = acc;
    }
}

/// NEON-blocked repack (16 rows/`vqtbl`). `B = −32·A`. Requires n % 16 == 0.
#[cfg(target_arch = "aarch64")]
pub struct Q6kBitplanesNeon {
    pub n: usize,
    pub d: usize,
    regions: usize,
    a: Vec<f32>,
    b: Vec<f32>,
    masks: Vec<u8>,
}

#[cfg(target_arch = "aarch64")]
pub fn q6k_to_bitplanes_neon(w: &[u8], n: usize, d: usize) -> Q6kBitplanesNeon {
    assert!(n.is_multiple_of(16), "NEON path requires n % 16 == 0");
    let regions = d / REGION;
    let blocks16 = n / 16;
    let mut a = vec![0.0f32; blocks16 * regions * 16];
    let mut b = vec![0.0f32; blocks16 * regions * 16];
    let mut masks = vec![0u8; blocks16 * regions * PLANES * GROUPS_PER_REGION * 16];
    let mut qval = vec![0u8; d];
    let mut arow = vec![0.0f32; regions];
    for r in 0..n {
        let blk = r / 16;
        let rib = r % 16;
        decode_q6k_row(w, r, d, &mut qval, &mut arow);
        for reg in 0..regions {
            a[(blk * regions + reg) * 16 + rib] = arow[reg];
            b[(blk * regions + reg) * 16 + rib] = -32.0 * arow[reg];
            for g in 0..GROUPS_PER_REGION {
                for plane in 0..PLANES {
                    let mut m = 0u8;
                    for i in 0..GROUP {
                        let q = qval[reg * REGION + g * GROUP + i];
                        m |= ((q >> plane) & 1) << i;
                    }
                    let idx = (((blk * regions + reg) * PLANES + plane) * GROUPS_PER_REGION + g) * 16 + rib;
                    masks[idx] = m;
                }
            }
        }
    }
    Q6kBitplanesNeon { n, d, regions, a, b, masks }
}

#[cfg(target_arch = "aarch64")]
pub fn mat_vec_q6k_lut_neon(out: &mut [f32], x: &[f32], bp: &Q6kBitplanesNeon) {
    use gnosis_frf::prelude::*;
    let regs = bp.regions;
    let mut lut = vec![0i8; regs * GROUPS_PER_REGION * 16];
    let mut sxq = vec![0.0f32; regs];
    let mut sx = vec![0.0f32; regs];
    for reg in 0..regs {
        let seg = &x[reg * REGION..reg * REGION + REGION];
        let mx = seg.iter().fold(0.0f32, |a, &v| a.max(v.abs()));
        let scale = if mx > 0.0 { mx / 31.0 } else { 1.0 };
        sxq[reg] = scale;
        sx[reg] = seg.iter().sum();
        for g in 0..GROUPS_PER_REGION {
            let base = &seg[g * GROUP..g * GROUP + GROUP];
            let o = &mut lut[(reg * GROUPS_PER_REGION + g) * 16..(reg * GROUPS_PER_REGION + g) * 16 + 16];
            for mm in 0..16usize {
                let mut acc = 0i32;
                for i in 0..GROUP {
                    if (mm >> i) & 1 == 1 {
                        acc += (base[i] / scale).round().clamp(-31.0, 31.0) as i32;
                    }
                }
                o[mm] = acc as i8;
            }
        }
    }
    out.par_chunks_mut(16).enumerate().for_each(|(blk, chunk)| unsafe {
        use std::arch::aarch64::*;
        let mut yacc = [vdupq_n_f32(0.0); 4];
        for reg in 0..regs {
            let mut p = [[vdupq_n_s32(0); 4]; PLANES];
            for plane in 0..PLANES {
                for g in 0..GROUPS_PER_REGION {
                    let tbl = vld1q_s8(lut.as_ptr().add((reg * GROUPS_PER_REGION + g) * 16));
                    let mbase = (((blk * regs + reg) * PLANES + plane) * GROUPS_PER_REGION + g) * 16;
                    let idx = vld1q_u8(bp.masks.as_ptr().add(mbase));
                    let v = vqtbl1q_s8(tbl, idx);
                    let lo16 = vmovl_s8(vget_low_s8(v));
                    let hi16 = vmovl_s8(vget_high_s8(v));
                    p[plane][0] = vaddq_s32(p[plane][0], vmovl_s16(vget_low_s16(lo16)));
                    p[plane][1] = vaddq_s32(p[plane][1], vmovl_s16(vget_high_s16(lo16)));
                    p[plane][2] = vaddq_s32(p[plane][2], vmovl_s16(vget_low_s16(hi16)));
                    p[plane][3] = vaddq_s32(p[plane][3], vmovl_s16(vget_high_s16(hi16)));
                }
            }
            let sxq_r = sxq[reg];
            let sx_r = sx[reg];
            for q in 0..4 {
                // qd = Σ_j 2^j p[j], j=0..5
                let qd = vaddq_s32(
                    vaddq_s32(
                        vaddq_s32(p[0][q], vshlq_n_s32(p[1][q], 1)),
                        vaddq_s32(vshlq_n_s32(p[2][q], 2), vshlq_n_s32(p[3][q], 3)),
                    ),
                    vaddq_s32(vshlq_n_s32(p[4][q], 4), vshlq_n_s32(p[5][q], 5)),
                );
                let qd_f = vmulq_n_f32(vcvtq_f32_s32(qd), sxq_r);
                let a16 = vld1q_f32(bp.a.as_ptr().add((blk * regs + reg) * 16 + q * 4));
                let b16 = vld1q_f32(bp.b.as_ptr().add((blk * regs + reg) * 16 + q * 4));
                yacc[q] = vfmaq_f32(yacc[q], a16, qd_f);
                yacc[q] = vfmaq_n_f32(yacc[q], b16, sx_r);
            }
        }
        for q in 0..4 {
            vst1q_f32(chunk.as_mut_ptr().add(q * 4), yacc[q]);
        }
    });
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::math::dequantize_q6k_row;

    fn random_q6k(n: usize, d: usize, seed: u64) -> Vec<u8> {
        let bpr = d / 256;
        let mut s = seed;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut w = vec![0u8; n * bpr * 210];
        for r in 0..n {
            for b in 0..bpr {
                let off = (r * bpr + b) * 210;
                for k in 0..208 {
                    w[off + k] = (rng() & 0xff) as u8;
                }
                w[off + 208..off + 210].copy_from_slice(&0x2e66u16.to_le_bytes()); // d ≈ 0.1
            }
        }
        w
    }

    #[test]
    fn q6k_lut_scalar_matches_dequant() {
        let (n, d) = (256usize, 512usize);
        let w = random_q6k(n, d, 0x6c6c);
        let mut s = 0x4321u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();

        // reference: dequantize each row then dot
        let mut y_ref = vec![0.0f32; n];
        let mut rowf = vec![0.0f32; d];
        for r in 0..n {
            dequantize_q6k_row(&mut rowf, &w, r, d);
            y_ref[r] = rowf.iter().zip(&x).map(|(a, b)| a * b).sum();
        }

        let bp = q6k_to_bitplanes(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        mat_vec_q6k_lut_scalar(&mut y_lut, &x, &bp);

        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!("[q6k-lut] scalar rel-L2 vs dequant+dot = {rel:.2e}");
        assert!(rel < 1e-4, "Q6_K scalar LUT must match dequant: rel={rel:.3e}");
    }

    #[cfg(target_arch = "aarch64")]
    #[test]
    fn q6k_lut_neon_matches_and_times() {
        use gnosis_frf::prelude::*;
        use std::time::Instant;
        let (n, d) = (4096usize, 4096usize);
        let w = random_q6k(n, d, 0x6eed);
        let mut s = 0x77u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();
        let reps = 30u128;

        // baseline: parallel dequant-then-dot (no fused Q6_K matvec in prod), buf reused per thread
        let mut y_ref = vec![0.0f32; n];
        let run_base = |y: &mut [f32]| {
            y.par_iter_mut().enumerate().for_each_init(
                || vec![0.0f32; d],
                |buf, (r, o)| {
                    dequantize_q6k_row(buf, &w, r, d);
                    *o = buf.iter().zip(&x).map(|(a, b)| a * b).sum();
                },
            );
        };
        for _ in 0..3 {
            run_base(&mut y_ref);
        }
        let t0 = Instant::now();
        for _ in 0..reps {
            run_base(&mut y_ref);
        }
        let prod = t0.elapsed().as_nanos() / reps;

        let bp = q6k_to_bitplanes_neon(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        for _ in 0..3 {
            mat_vec_q6k_lut_neon(&mut y_lut, &x, &bp);
        }
        let t1 = Instant::now();
        for _ in 0..reps {
            mat_vec_q6k_lut_neon(&mut y_lut, &x, &bp);
        }
        let lut = t1.elapsed().as_nanos() / reps;

        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!(
            "[q6k-lut NEON] {n}x{d}: dequant+dot {:.1}us  lut {:.1}us  speedup {:.2}x  rel-L2 {:.2e}",
            prod as f64 / 1e3,
            lut as f64 / 1e3,
            prod as f64 / lut as f64,
            rel
        );
        assert!(rel < 0.06, "Q6_K neon LUT rel-L2 too high: {rel:.3e}");
    }
}
